const d = $('Obtener Scorecard').first().json;
const semaforo = d.kpis?.salud === 'verde' ? '🟢' : d.kpis?.salud === 'amarillo' ? '🟡' : '🔴';
const fmt = n => n ? n.toLocaleString('es-MX', {minimumFractionDigits:2}) : '0.00';
let msg = `📊 *Scorecard Semanal — Fourgea*\n`;
msg += `📅 ${d.periodo || new Date().toISOString().slice(0,7)}\n\n`;
msg += `${semaforo} Salud financiera: *${(d.kpis?.salud || 'N/A').toUpperCase()}*\n\n`;
msg += `📈 Margen bruto: ${d.margen_bruto_pct?.toFixed(1) || 'N/A'}%\n`;
msg += `⏱️ Días prom. pago: ${d.dias_promedio_pago?.toFixed(0) || 'N/A'} días\n`;
msg += `🧾 IVA generado: $${fmt(d.iva_generado_mes)} MXN\n`;
msg += `📋 Facturas pendientes: ${d.facturas_pendientes || 0} ($${fmt(d.monto_pendiente)})\n`;
if (d.alertas?.length) {
  msg += `\n⚠️ Alertas:\n`;
  d.alertas.forEach(a => { msg += `• ${a}\n`; });
}
msg += '\n👉 sonoradigitalcorp.com/panel';
return [{ json: { mensaje: msg, numero: '526622681111' } }];
